// src/components/Home.js
import React, { useState } from "react";
import "./Home.css"; // Импортируем CSS файл
import TreeView from "react-treeview"; // Импортируем библиотеку для отображения дерева

// Пример иерархической структуры директорий и файлов
const directories = [
    {
        name: "Documents",
        children: [
            {
                name: "Work",
                children: [
                    { name: "report.docx", type: "file" },
                    { name: "budget.xlsx", type: "file" },
                ],
            },
            {
                name: "Personal",
                children: [
                    { name: "letter.txt", type: "file" },
                    { name: "cv.pdf", type: "file" },
                ],
            },
        ],
    },
    {
        name: "Downloads",
        children: [
            {
                name: "Images",
                children: [
                    { name: "photo1.jpg", type: "file" },
                    { name: "photo2.png", type: "file" },
                ],
            },
            {
                name: "Videos",
                children: [
                    { name: "video1.mp4", type: "file" },
                    { name: "video2.mkv", type: "file" },
                ],
            },
        ],
    },
];

const Home = () => {
    const [selectedDir, setSelectedDir] = useState(null);
    const [selectedFile, setSelectedFile] = useState(null);

    const handleDirectorySelect = (dir) => {
        setSelectedDir(dir);
        setSelectedFile(null);
    };

    const handleFileSelect = (file) => {
        setSelectedFile(file);
    };

    // Рекурсивная функция для рендеринга дерева директорий
    const renderTree = (data) => {
        return data.map((node, idx) => {
            if (node.type === "file") {
                return (
                    <div key={idx} className="file-item">
                        <button
                            className="button"
                            onClick={() => handleFileSelect(node.name)}
                        >
                            {node.name}
                        </button>
                    </div>
                );
            } else {
                return (
                    <TreeView nodeLabel={node.name} key={idx}>
                        {renderTree(node.children)}
                    </TreeView>
                );
            }
        });
    };

    return (
        <div className="container">
            <div className="content-wrapper">
                {/* Боковой раздел */}
                <div className="sidebar">
                    <h3>Директории</h3>
                    <div>{renderTree(directories)}</div>
                </div>

                {/* Основной раздел */}
                <div className="mainContent">
                    {selectedDir ? (
                        <>
                            <h3>Файлы в {selectedDir.name}</h3>
                            <ul className="fileList">
                                {selectedDir.children &&
                                    selectedDir.children.map((subDir, idx) => (
                                        <div key={idx}>
                                            <h4>{subDir.name}</h4>
                                            <ul>
                                                {subDir.children.map(
                                                    (file, fileIdx) => (
                                                        <li key={fileIdx}>
                                                            <button
                                                                className="button"
                                                                onClick={() =>
                                                                    handleFileSelect(
                                                                        file.name
                                                                    )
                                                                }
                                                            >
                                                                {file.name}
                                                            </button>
                                                        </li>
                                                    )
                                                )}
                                            </ul>
                                        </div>
                                    ))}
                            </ul>
                        </>
                    ) : (
                        <p>Выберите директорию для отображения файлов.</p>
                    )}
                </div>
            </div>

            {/* Нижний раздел */}
            <div className="footer">
                {selectedFile ? (
                    <div>
                        <h4>Содержимое файла: {selectedFile}</h4>
                        <p>Здесь будет отображаться содержимое файла...</p>
                    </div>
                ) : (
                    <p>Выберите файл для просмотра содержимого.</p>
                )}
            </div>
        </div>
    );
};

export default Home;
